import React, { useState } from "react";
import "./FormPage.css";
import axios from "axios";

const FormPage = ({ response }) => {
 if(!response){
  console.log("------>response",response);
 }else{
  console.log("data not passsed")
 }

  //States for all the fields
  const [formdata,setFormdata] = useState({
    name: "",
    phone: "",
    pickup: "",
    destination: "",
    weight: "",
    date: "",
    time: "",
    vehicle: "",
    price: ""
  });
  const [responseMessage, setResponseMessage] = useState('');
  const [errorMessage, setErrorMessage] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault(); // Prevent the default form submission behavior

    try {
      const result = await axios.post('https://bidwheels-api-env.eba-ts5rcstj.us-east-1.elasticbeanstalk.com/user/createOrder/1', formdata);
      console.log('Response:', result.data);

      // Set response message or perform additional actions
      setResponseMessage('Form submitted successfully!');
      setErrorMessage('');
    } catch (error) {
      console.error('Error:', error);
      setErrorMessage('Failed to submit the form. Please try again.');
      setResponseMessage('');
      console.logg("------->>",)
    }
  };
    
  return (
    <div className="app-container">
      <div className="grid-container">
       <header className="header">
        <div className="logo">TRUXGO</div>
        <div className="user-icon">👤</div>
      </header>
      
        <div className="sidebar">
      <div className="sidebar-item">
        
        <span className="text">New Order</span>
      </div>
      <div className="menu-item">BidLists</div>
      <div className="sidebar-item">
       
        <span className="text">Order History</span>
      </div>
    </div>
    <div className="form-container">
      <h2 className="form-title">Load Detail</h2>
      <form className="load-form" onSubmit={handleSubmit}>
        <div className="form-row">
          <div className="form-group">
            <label>Name</label>
            <input
             type="text"
            placeholder="Enter name"
            value={formdata.name}
            onChange={(e) => setFormdata({ ...formdata, name: e.target.value })} 
            />
          </div>
          <div className="form-group">
            <label>Phone number</label>
            <input
            type="text" 
            placeholder="Enter phone number"
            value={formdata.phone}
            onChange={(e) => setFormdata({ ...formdata, phone: e.target.value })}
            />
          </div>
        </div>
        <div className="form-row">
          <div className="form-group">
            <label>Pickup Location</label>
            <input 
            type="text" 
            placeholder="Enter pickup location" 
            value={formdata.pickup}
            onChange={(e) => setFormdata({ ...formdata, pickup: e.target.value })}
            />
          </div>
          <div className="form-group">
            <label>Drop Location</label>
            <input 
            type="text" 
            placeholder="Enter drop location" 
            value={formdata.destination}
            onChange={(e) => setFormdata({ ...formdata, destination: e.target.value })}
            />
          </div>
        </div>
        <div className="form-row">
          <div className="form-group">
            <label>Load Type</label>
            <select
            placeholder="Select load type"
            value={formdata.type}
            onChange={(e) => setFormdata({ ...formdata, type: e.target.value })}
            >
              <option value="" disabled selected>Choose Load Type</option>
              <option  value="type1">More than 2 Ton</option>
              <option value="type2">Less than 2 Ton</option>
            </select>
          </div>
          <div className="form-group">
            <label>Load Weight</label>
            <input 
            type="text" 
            placeholder="Enter load weight" 
            value={formdata.weight}
            onChange={(e) => setFormdata({ ...formdata, weight: e.target.value })}
            />
          </div>
        </div>
        <div className="form-row">
          <div className="form-group">
            <label>Pickup Date</label>
            <input 
            type="date" 
            value={formdata.date}
            onChange={(e) => setFormdata({ ...formdata, date: e.target.value })}
            />
          </div>
          <div className="form-group">
            <label>Delivery Date</label>
            <input 
            type="date" 
            value={formdata.date}
            onChange={(e) => setFormdata({ ...formdata, date: e.target.value })}
            />
          </div>
        </div>
        
        <div className="form-row">
          <div className="form-group full-width">
            <label>Description</label>
            <textarea 
            placeholder="Enter description"
            value={formdata.description}
            onChange={(e) => setFormdata({ ...formdata, description: e.target.value })}
            ></textarea>
          </div>
        </div>
        <button type="submit" className="submit-button">Submit</button>
      </form>
    </div>
    </div>
    </div>
  );
}



export default FormPage;
